import java.util.Scanner;

public class BufferOverflowVulnerability {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Vulnerable code - creating an array with fixed size without proper input validation
        char[] buffer = new char[10];

        // Copy user input into the buffer without checking input size
        for (int i = 0; i < userInput.length(); i++) {
            buffer[i] = userInput.charAt(i);
        }

        System.out.println("Buffer content: " + String.valueOf(buffer));
    }
}

